const body = $json.body || $json;
const changes = body.entry?.[0]?.changes?.[0]?.value || {};
const messages = changes.messages || [];

// LIVE-only: drop test number traffic so dev handles it exclusively
// Test number 1002910989571888 is shared between live and dev Meta apps
const incomingPhoneId = changes.metadata?.phone_number_id || '';
if (incomingPhoneId === '1002910989571888') {
  // Silently drop — dev workflow will handle this message
  return [];
}

if (messages.length === 0) return [];

const msg = messages[0];
const senderPhone = msg.from;

// Handle interactive button replies (video_yes/no + media ticket selection)
if (msg.type === 'interactive' && msg.interactive?.button_reply) {
  const buttonTitle = (msg.interactive.button_reply.title || '').toLowerCase().trim();
  const buttonId = msg.interactive.button_reply.id || '';
  let action = '';
  if (buttonTitle === 'yes') action = 'video_yes';
  else if (buttonTitle === 'no') action = 'video_no';
  else action = buttonId;
  return [{ json: { senderPhone, text: '', messageId: msg.id, buttonReplyId: action, isCallback: true } }];
}

// Handle interactive list replies (media ticket selection)
if (msg.type === 'interactive' && msg.interactive?.list_reply) {
  const listId = msg.interactive.list_reply.id || '';
  return [{ json: { senderPhone, text: '', messageId: msg.id, buttonReplyId: listId, isCallback: true } }];
}

// Handle template quick reply buttons
if (msg.type === 'button' && msg.button) {
  const buttonText = (msg.button.text || '').toLowerCase().trim();
  const buttonPayload = msg.button.payload || '';
  let action = '';
  if (buttonText === 'yes' || buttonPayload === 'yes') action = 'video_yes';
  else if (buttonText === 'no' || buttonPayload === 'no') action = 'video_no';
  else action = buttonPayload || buttonText;
  return [{ json: { senderPhone, text: '', messageId: msg.id, buttonReplyId: action, isCallback: true } }];
}

// Handle media (image, video, document, audio)
if (['image', 'video', 'document', 'audio'].includes(msg.type)) {
  const mediaObj = msg[msg.type] || {};
  const caption = mediaObj.caption || '';
  return [{ json: {
    senderPhone, text: caption, messageId: msg.id,
    isCallback: false, isMedia: true,
    mediaType: msg.type, mediaId: mediaObj.id || ''
  }}];
}

const text = msg.text?.body || msg.caption || '';
if (!text.trim()) return [];

return [{ json: { senderPhone, text, messageId: msg.id, isCallback: false, isMedia: false } }];

const input = $input.first().json;
const buttonId = input.buttonReplyId || '';
const phone = (input.senderPhone || '').replace(/[^0-9]/g, '');

if (!buttonId || !phone) return [{ json: { handled: false, reason: 'no button or phone' } }];

const isFrench = false;
let msg = '';
let resolveTicket = false;
let isMediaCallback = false;
let mediaTicketId = '';
let mediaShortId = '';

if (buttonId.startsWith('video_yes')) {
  msg = isFrench
    ? "Super! Content que la vidéo ait aidé. Si vous avez d'autres questions, n'hésitez pas."
    : 'Great! Glad the video helped. If you have any other questions, feel free to reach out.';
  resolveTicket = true;
} else if (buttonId.startsWith('video_no')) {
  msg = isFrench
    ? "Pas de souci! Quelqu'un de notre équipe vous contactera bientôt."
    : 'No worries! Someone from our team will follow up with you soon.';
} else if (buttonId.startsWith('mc||')) {
  // Media category/ticket callback
  const parts = buttonId.split('||');
  mediaTicketId = parts[1] || '';
  mediaShortId = parts[2] || '';
  isMediaCallback = true;
  msg = '';
}

if (!msg && !isMediaCallback) return [{ json: { handled: false, reason: 'unknown button: ' + buttonId } }];

return [{ json: { handled: true, action: buttonId, phone, resolveTicket, msg, isMediaCallback, mediaTicketId, mediaShortId } }];

const cb = $('Handle WA Callback').item.json;
const rt = $input.first().json;
const ticketId = rt.ticket_id || '';
let msg = cb.msg || '';
if (ticketId && cb.resolveTicket) {
  msg = 'Ticket ' + ticketId + ' has been closed. ' + msg;
}
return [{ json: { phone: cb.phone, message: msg, ticketId, resolveTicket: cb.resolveTicket } }];

const parsed = $('Parse Meta Message').item.json;
const pending = $('Save WA Pending Media').item.json;
const tickets = $('Get WA Tickets').all().map(i => i.json).filter(t => t.ticket_id);
const phone = parsed.senderPhone;
const shortId = pending.id.slice(-12);

const token = $env.WHATSAPP_TOKEN || '';

if (tickets.length > 0) {
  const rows = tickets.map(t => ({
    id: 'mc||' + t.ticket_id + '||' + shortId,
    title: t.ticket_id,
    description: (t.keywords || t.category || '').replace(/_/g, ' ').slice(0, 72)
  }));

  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${$env.WHATSAPP_PHONE_NUMBER_ID}/messages`,
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
    body: {
      messaging_product: 'whatsapp', to: phone, type: 'interactive',
      interactive: {
        type: 'list',
        body: { text: '📸 Photo received! Which ticket is this for?' },
        action: { button: 'Select ticket', sections: [{ title: 'Open Tickets', rows: rows }] }
      }
    },
    json: true
  });
} else {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${$env.WHATSAPP_PHONE_NUMBER_ID}/messages`,
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token },
    body: { messaging_product: 'whatsapp', to: phone, type: 'text',
      text: { body: '📸 Photo received! Please describe the issue first, then resend the photo.' }
    },
    json: true
  });
}

return [{ json: { sent: true, phone, pendingId: pending.id, ticketCount: tickets.length } }];

const pending = $('Save WA Pending Media').item.json;
const fileId = pending.file_id;
if (!fileId) return [{ json: { saved: false } }];

const token = $env.WHATSAPP_TOKEN || '';

const mediaInfo = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://graph.facebook.com/v21.0/' + fileId,
  headers: { 'Authorization': 'Bearer ' + token },
  json: true
});

const downloadUrl = mediaInfo.url;
if (!downloadUrl) return [{ json: { saved: false } }];

const fileBuffer = await this.helpers.httpRequest({
  method: 'GET',
  url: downloadUrl,
  headers: { 'Authorization': 'Bearer ' + token },
  encoding: 'arraybuffer',
  returnFullResponse: false,
  json: false
});

const ext = (mediaInfo.mime_type || 'image/jpeg').split('/').pop() || 'jpg';
const filename = Date.now() + '_' + Math.random().toString(36).slice(2,8) + '.' + ext;
const filePath = '/files/media/' + filename;

const fs = require('fs');
fs.writeFileSync(filePath, Buffer.from(fileBuffer));

return [{ json: { saved: true, filename, url: '/api/media/' + filename, chatId: pending.chat_id, pendingId: pending.id, mimeType: mediaInfo.mime_type || 'image/jpeg' } }];
